      "blocking": false,
      "confidence": 1.0,
      "evidence_refs": []
    }
  ],
  "overall_fulfillment": {
    "status": "not_fulfilled",
    "summary": "意图识别API服务不可用，未返回意图标签和置信度，所有核心期望均未满足。"
  },
  "expected": {
    "intent": "customer_portrait",
    "confidence": 0.95,
    "target_value": "重疾险"
  },
  "missing": [
