      "expected": "customer_portrait",
      "actual": null,
      "evidence_ref": "execution_trace.label_mapping.intent",
      "raw": null,
      "incomplete": true
    },
    {
      "kind": "confidence",
      "error_type": "missing",
      "expected": 0.95,
      "actual": null,
      "evidence_ref": "execution_trace.adapter_extraction",
      "raw": null,
